// COMPLETE, COMPILABLE C code
// Uses correct I/O
// Handles all T test cases
#include <stdio.h>
#include <string.h>
#define MAX 150
#define MAX_DIR 4

char directs[MAX][MAX][MAX_DIR + 1];
char chosen[MAX][MAX];
int N;

void dfs(int i, int j) {
    if (chosen[i][j] != 0) return;
    for (int k = 0; k < strlen(directs[i][j]); k++) {
        char dir = directs[i][j][k];
        int ni = i, nj = j;
        if (dir == 'U') ni--;
        else if (dir == 'D') ni++;
        else if (dir == 'L') nj--;
        else nj++;
        if (ni < 0 || ni >= N || nj < 0 || nj >= N) continue;
        chosen[i][j] = dir;
        dfs(ni, nj);
    }
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                scanf("%s", directs[i][j]);
            }
        }
        memset(chosen, 0, sizeof(chosen));
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                dfs(i, j);
            }
        }
        int ok = 1;
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                if (chosen[i][j] == 0) {
                    ok = 0;
                    break;
                }
            }
            if (!ok) break;
        }
        if (ok) {
            printf("YES\n");
            for (int i = 0; i < N; i++) {
                for (int j = 0; j < N; j++) {
                    printf("%c ", chosen[i][j]);
                }
                printf("\n");
            }
        } else {
            printf("NO\n");
        }
    }
    return 0;
}

